import React, { useEffect, useState } from 'react';
import { db } from '../firebase';
import { collection, getDocs, doc, deleteDoc } from 'firebase/firestore';
import { useNavigate } from 'react-router-dom';

function TeamsManagement() {
  const [teams, setTeams] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchTeams = async () => {
      const teamsCollection = await getDocs(collection(db, 'teams'));
      const teamsData = teamsCollection.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
      }));
      setTeams(teamsData);
    };

    fetchTeams();
  }, []);

  const handleEditTeam = (team) => {
    const userPin = prompt("Enter PIN to edit:");
    if (userPin === team.pin) {
      navigate(`/edit-team/${team.id}`);
    } else {
      alert("Incorrect PIN.");
    }
  };

  const handleDeleteTeam = async (team) => {
    const userPin = prompt("Enter PIN to delete:");
    if (userPin === team.pin) {
      await deleteDoc(doc(db, 'teams', team.id));
      alert('Team deleted!');
      setTeams(teams.filter(t => t.id !== team.id));
    } else {
      alert("Incorrect PIN.");
    }
  };

  const handleLineup = (teamId) => {
    navigate(`/team-lineup/${teamId}`);
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Teams Management</h1>

      <button style={styles.createButton} onClick={() => navigate('/create-team')}>
        Create New Team
      </button>

      {teams.length === 0 ? (
        <p style={styles.noTeams}>Create the first Team!</p>
      ) : (
        <div style={styles.teamList}>
          {teams.map(team => (
            <div key={team.id} style={{ ...styles.teamCard, backgroundColor: team.color }}>
              <h3>{team.name}</h3>
              <p><strong>Entrance Song:</strong> <a href={team.entranceSong} target="_blank">Listen</a></p>
              <img
                src={`${process.env.PUBLIC_URL}/images/Tactics/${team.playerCount}_players_${team.tactic}.png`}
                alt="Tactic"
                style={styles.tacticImage}
              />
              <div style={styles.buttonGroup}>
                <button style={styles.editButton} onClick={() => handleEditTeam(team)}>Edit</button>
                <button style={styles.removeButton} onClick={() => handleDeleteTeam(team)}>Remove</button>
                <button style={styles.lineupButton} onClick={() => handleLineup(team.id)}>Lineup</button>
              </div>
            </div>
          ))}
        </div>
      )}

      <button style={styles.backButton} onClick={() => navigate('/')}>Back to Main Menu</button>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
  },
  title: { fontSize: '24px' },
  createButton: { backgroundColor: '#386C0B', padding: '10px' },
  noTeams: { marginTop: '20px' },
  teamList: { display: 'flex', gap: '20px', flexWrap: 'wrap', justifyContent: 'center' },
  teamCard: { width: '250px', padding: '20px', borderRadius: '10px' },
  tacticImage: { width: '100%', height: '150px', objectFit: 'cover' },
  buttonGroup: { display: 'flex', justifyContent: 'space-between', marginTop: '10px' },
  editButton: { backgroundColor: '#7FC6A4' },
  removeButton: { backgroundColor: '#FF4D4D' },
  lineupButton: { backgroundColor: '#5D737E' },
  backButton: { marginTop: '20px' },
};

export default TeamsManagement;
